after.code:
onError: (error) => {
  if (isTRPCClientError(error)) {
    const { code } = parseTrpcError(error);
    toast.error(translateServiceErrorCode(t, code));
    return;
  }
  toast.error(t("error.codes.UNKNOWN"));
}

children.code:
codes: {
  // ...existing keys...
  USER_ALREADY_EXISTS:
    "This account is already registered. Please sign in or use a different account.",
  LOGIN_FAILED: "Login failed.",
  CHECK_TOKEN_FAILED: "Token validation failed.",
  TOKEN_EXPIRED: "Your session has expired.",
  UNAUTHORIZED: "You are not authorized.",
}

import { isTRPCClientError } from "@trpc/react-query";
import { parseTrpcError } from "@/app/components/trpc-error-panel";
import { translateServiceErrorCode } from "@/library/i18n/translate-service-error-code";

const registerMutation = trpc.register.register.useMutation({
  onSuccess: () => {
    toast.success(t("register.success"));
    router.push("/");
  },
  onError: (error) => {
    if (isTRPCClientError(error)) {
      const { code } = parseTrpcError(error);
      toast.error(translateServiceErrorCode(t, code));
      return;
    }
    toast.error(t("error.codes.UNKNOWN"));
  },
});

import { TRPCError } from "@trpc/server";
import { isServiceError } from "@/library/services/error";

try {
  return await registerService.register(input);
} catch (err) {
  if (isServiceError(err)) {
    throw new TRPCError({
      code: "CONFLICT",
      message: err.code,
      cause: err,
    });
  }
  throw err;
}
